function applyResist(damage: number, resist: number): number {
  return Math.round(damage * (1 - Math.min(0.75, resist / 100)))
}

const fireDmg = applyResist(playerStats.fireDamage ?? 0, monster.fireResist ?? 0)
const coldDmg = applyResist(playerStats.coldDamage ?? 0, monster.coldResist ?? 0)
const lightDmg = Math.round(applyResist(playerStats.lightningDamage ?? 0, monster.lightResist ?? 0) * 1.25) // lightning bypasses 25% defense
